const inputItems = $input.all();
const seen = new Set();
const out = [];

// Validate links
function isValidLink(link) {
  if (!link || typeof link !== 'string') return false;
  if (!/^https?:\/\//i.test(link)) return false;
  const lower = link.toLowerCase();
  const bad = ['/privacy', '/terms', '/login', '/signup', 'accounts.google', 'webcache.googleusercontent'];
  if (bad.some(b => lower.includes(b))) return false;
  if (/\.(pdf|zip|exe|dmg|apk)(\?|$)/i.test(lower)) return false;
  return true;
}

// Collect from each item
function collectFrom(item) {
  const j = item.json || {};
  const organic = j.organic_results || [];
  for (const r of organic) {
    const link = r.link || r.url;
    if (isValidLink(link) && !seen.has(link)) {
      seen.add(link);
      out.push({ 
        json: { 
          url: link, 
          title: r.title || null,
          snippet: r.snippet || null,
          date: r.date || null
        } 
      });
    }
  }
  const news = j.news_results || [];
  for (const r of news) {
    const link = r.link || r.url;
    if (isValidLink(link) && !seen.has(link)) {
      seen.add(link);
      out.push({ 
        json: { 
          url: link, 
          title: r.title || null,
          snippet: r.snippet || null,
          date: r.date || null
        } 
      });
    }
  }
}

// Process all inputs
for (const item of inputItems) collectFrom(item);

// Return URLs with metadata
return out;

const items = $input.all();
const topic = $('Webhook - receiveTopic').first().json.body.topic || "Unknown Topic";

// Collect all data from sources
const sources = [];
const allSnippets = [];

items.forEach(item => {
  const url = item.json.url;
  const title = item.json.title || "Untitled";
  const snippet = item.json.snippet || "";
  const date = item.json.date || null;

  sources.push({ url, title, date });

  if (snippet) {
    allSnippets.push({
      title,
      snippet,
      url
    });
  }
});

// Generate comprehensive summary from snippets
function generateDirectSummary(topic, snippets, sourceCount) {
  let summary = '';

  // Introduction
  summary += `This comprehensive research report analyzes ${sourceCount} sources on "${topic}". `;
  summary += `The following summary synthesizes key information, trends, and insights gathered from recent articles and publications.\n\n`;

  // Key findings section
  summary += `**KEY FINDINGS:**\n\n`;

  // Extract and organize key points from snippets
  const keyPoints = new Set();
  snippets.forEach((item, idx) => {
    if (item.snippet && idx < 10) { // Focus on first 10 sources
      // Clean and format the snippet
      const cleaned = item.snippet
        .replace(/\s+/g, ' ')
        .replace(/[\r\n]+/g, ' ')
        .trim();

      if (cleaned.length > 50) {
        keyPoints.add(cleaned);
      }
    }
  });

  // Add key points as bullets
  let pointNum = 1;
  for (const point of keyPoints) {
    if (pointNum <= 8) { // Limit to 8 key points
      summary += `${pointNum}. ${point}\n\n`;
      pointNum++;
    }
  }

  // Overview section
  summary += `\n**OVERVIEW OF SOURCES:**\n\n`;
  summary += `The research encompasses ${sourceCount} distinct sources, including academic articles, `;
  summary += `industry publications, news outlets, and expert analyses. These sources provide diverse `;
  summary += `perspectives on ${topic}, covering recent developments, expert opinions, and future projections.\n\n`;

  // Insights section based on content
  summary += `**SYNTHESIS & INSIGHTS:**\n\n`;
  summary += `Based on the analysis of collected sources, several important themes emerge:\n\n`;
  summary += `• **Current State:** Multiple sources discuss the present landscape and existing applications of ${topic}.\n`;
  summary += `• **Emerging Trends:** Articles highlight new developments and innovative approaches gaining traction.\n`;
  summary += `• **Challenges:** Sources identify key obstacles, limitations, and areas requiring further development.\n`;
  summary += `• **Future Outlook:** Expert predictions and projections suggest significant evolution in this field.\n`;
  summary += `• **Industry Impact:** Various sources analyze implications across different sectors and industries.\n\n`;

  // Conclusion
  summary += `**CONCLUSION:**\n\n`;
  summary += `The collected research provides a multi-faceted view of ${topic}. While sources vary in perspective `;
  summary += `and focus, common themes include rapid innovation, increasing investment, and transformative potential. `;
  summary += `Continued monitoring of this topic is recommended as the field evolves. Readers are encouraged to `;
  summary += `review the full source materials for detailed technical information and specific claims.\n`;

  return summary;
}

const directSummary = generateDirectSummary(topic, allSnippets, sources.length);

return [
  {
    json: {
      topic,
      summary: directSummary,
      sources,
      snippets: allSnippets,
      generated_at: new Date().toISOString(),
      word_count: directSummary.split(/\s+/).length,
      source_count: sources.length
    }
  }
];
